class PluginManager:
    """Manages plugin discovery, loading, and lifecycle via process isolation."""

    def __init__(
        self,
        plugin_interface:Type[PluginInterface]=PluginInterface, # Base interface for type checking
        search_paths:Optional[List[Path]]=None, # Custom manifest search paths
        scheduler:Optional[ResourceScheduler]=None, # Resource allocation policy
        config_store:Optional[PluginConfigStore]=None # CR-2: persistence backend; lazy LocalPluginConfigStore default per OQ-4
    ):
        """Initialize the plugin manager."""
        self.plugin_interface = plugin_interface
        
        # Use config-based search paths if not explicitly provided
        if search_paths is None:
            cfg = get_config()
            self.search_paths = [
                Path.cwd() / ".cjm" / "manifests",  # Local (high priority)
                cfg.manifests_dir                    # Config-based (replaces ~/.cjm/manifests)
            ]
        else:
            self.search_paths = search_paths
        
        self.scheduler = scheduler or PermissiveScheduler()
        self.system_monitor: Optional[PluginInterface] = None
        self.discovered: List[PluginMeta] = []
        self.plugins: Dict[str, PluginMeta] = {}
        # CR-10: per-instance state keyed by instance_id. Default-loaded plugins
        # populate self.instances[plugin_name] alongside self.plugins[plugin_name]
        # for backward compat; multi-instance loads populate self.instances only.
        self.instances: Dict[str, PluginInstance] = {}
        self.logger = logging.getLogger(f"{__name__}.{type(self).__name__}")
        
        # CR-2: persistence + lifecycle hook bookkeeping.
        # config_store=None → lazy LocalPluginConfigStore (~/.cjm/plugin_configs.db)
        # per OQ-4 resolution. Hosts that want a different backend (workflow-
        # scoped, in-memory for tests) pass an explicit PluginConfigStore.
        self.config_store: PluginConfigStore = config_store or LocalPluginConfigStore()
        # Track plugins with in-flight execute calls so disable_plugin can defer
        # the on_disable hook until the job finishes (audit semantics).
        self._running_executions: Set[str] = set()
        self._pending_disable_hooks: Set[str] = set()

    def register_system_monitor(
        self,
        plugin_name:str # Name of the system monitor plugin
    ) -> None:
        """Bind a loaded plugin to act as the hardware system monitor."""
        self.system_monitor = self.get_plugin(plugin_name)
        if self.system_monitor:
            self.logger.info(f"Registered system monitor: {plugin_name}")
        else:
            self.logger.warning(f"System monitor plugin not found: {plugin_name}")

    def _get_global_stats(self) -> Dict[str, Any]: # Current system telemetry
        """Fetch real-time stats from the system monitor plugin (sync).
        
        CR-3: prefer typed `get_system_status()` over magic-string dispatcher.
        Duck-types because the substrate references `system_monitor` as a
        generic `PluginInterface` — CR-1's host-no-imports rule means substrate
        does not import `cjm-infra-plugin-system` to type-narrow the reference.
        Proxies after CR-3 expose `get_system_status` as a bound method that
        POSTs to `/get_system_status` and returns `Optional[Dict[str, Any]]`.
        """
        if not self.system_monitor:
            return {}
        # CR-3: prefer typed call
        get_status = getattr(self.system_monitor, "get_system_status", None)
        if callable(get_status):
            try:
                result = get_status()
                if isinstance(result, dict):
                    return result
                if hasattr(result, "to_dict"):  # In-process plugin returning SystemStats directly
                    return result.to_dict()
                if result is None:
                    return {}  # Worker unreachable (proxy already logged ConnectError)
                self.logger.warning(
                    f"get_system_status returned unexpected type: {type(result).__name__}"
                )
                return {}
            except Exception as e:
                self.logger.warning(f"Typed get_system_status failed: {e}")
                return {}
        # REMOVE-AFTER-OVERHAUL: pre-CR-3 dispatcher fallback. Only fires when
        # the configured system_monitor lacks get_system_status attribute
        # (e.g., an in-process non-MonitorPlugin object — configuration error).
        # SG-47 cascade ensures all real monitors expose the typed surface;
        # SG-48 sweep drops this branch entirely.
        try:
            return self.system_monitor.execute("get_system_status")
        except Exception as e:
            self.logger.warning(f"Failed to fetch system stats (dispatcher fallback): {e}")
        return {}

    async def _get_global_stats_async(self) -> Dict[str, Any]: # Current system telemetry
        """Fetch real-time stats from the system monitor plugin (async).
        
        Same CR-3 duck-type semantics as the sync variant. Async variant exists
        because the substrate's `execute_plugin_async` path (CR-2 + CR-10) needs
        a non-blocking stats fetch when scheduling under an asyncio event loop.
        """
        if not self.system_monitor:
            return {}
        # CR-3: prefer typed call
        get_status_async = getattr(self.system_monitor, "get_system_status_async", None)
        if callable(get_status_async):
            try:
                result = await get_status_async()
                if isinstance(result, dict):
                    return result
                if hasattr(result, "to_dict"):
                    return result.to_dict()
                if result is None:
                    return {}  # Worker unreachable (proxy already logged ConnectError)
                self.logger.warning(
                    f"get_system_status_async returned unexpected type: {type(result).__name__}"
                )
                return {}
            except Exception as e:
                self.logger.warning(f"Typed get_system_status_async failed: {e}")
                return {}
        # REMOVE-AFTER-OVERHAUL: pre-CR-3 dispatcher fallback (see sync variant)
        try:
            return await self.system_monitor.execute_async("get_system_status")
        except Exception as e:
            self.logger.warning(f"Failed to fetch system stats (dispatcher fallback): {e}")
        return {}

    def _check_interface_fqn(
        self,
        iface_fqn:str, # Interface FQN string from the manifest
        plugin_name:str # For error messages
    ) -> bool: # True if FQN passes the format check
        """SG-7: sanity-check the interface FQN format at discovery time.
        
        Substrate cannot actually import every interface library (the host
        env doesn't carry them all), so this is a format-only check. The
        authoritative import check happens at install time in
        _generate_manifest's introspection script.
        """
        if not iface_fqn:
            self.logger.warning(
                f"Plugin {plugin_name!r}: manifest has empty `interface` field. "
                f"Run `cjm-ctl regenerate-manifest {plugin_name}` to refresh."
            )
            return False
        if "." not in iface_fqn:
            self.logger.warning(
                f"Plugin {plugin_name!r}: malformed interface FQN {iface_fqn!r} "
                f"(expected dotted path like 'module.subpackage.ClassName'). "
                f"Run `cjm-ctl regenerate-manifest {plugin_name}` to refresh."
            )
            return False
        return True

    def _parse_taxonomy(
        self,
        manifest: Dict[str, Any]  # Loaded manifest dict
    ) -> Optional[PluginTaxonomy]:
        """CR-1: parse the manifest's taxonomy block into a PluginTaxonomy.
        
        Returns None when the manifest predates CR-1 (no taxonomy block).
        """
        tax_dict = manifest.get("taxonomy")
        if not tax_dict or not isinstance(tax_dict, dict):
            return None
        return PluginTaxonomy(
            domain=tax_dict.get("domain", ""),
            role=tax_dict.get("role", ""),
            interface_fqcn=tax_dict.get("interface_fqcn", manifest.get("interface", "")),
        )

    def _parse_resources(
        self,
        manifest: Dict[str, Any]  # Loaded manifest dict
    ) -> Optional[ResourceRequirements]:
        """Phase 5a: parse the manifest's resources block into a ResourceRequirements."""
        res_dict = manifest.get("resources")
        if not res_dict or not isinstance(res_dict, dict):
            return None
        return ResourceRequirements(
            requires_gpu=bool(res_dict.get("requires_gpu", False)),
            platforms=list(res_dict.get("platforms", [])),
            accelerators=list(res_dict.get("accelerators", [])),
        )

    def _derive_category(
        self,
        manifest: Dict[str, Any],  # Loaded manifest dict
        taxonomy: Optional[PluginTaxonomy]  # Parsed taxonomy (or None for legacy manifests)
    ) -> str:
        """CR-1: derive the human-readable category label.
        
        Resolution: category_override > Title-Case of taxonomy.domain (with
        underscores → spaces) > legacy `category` field > empty.
        """
        override = manifest.get("category_override")
        if isinstance(override, str) and override:
            return override
        if taxonomy and taxonomy.domain:
            return taxonomy.domain.replace("_", " ").title()
        legacy = manifest.get("category", "")
        return legacy if isinstance(legacy, str) else ""

    def discover_manifests(self) -> List[PluginMeta]: # List of discovered plugin metadata
        """Discover plugins via JSON manifests in search paths."""
        self.discovered = []
        seen_plugins = set()

        for base_path in self.search_paths:
            if not base_path.exists():
                continue
            
            for manifest_file in base_path.glob("*.json"):
                try:
                    with open(manifest_file) as f:
                        manifest = json.load(f)
                    
                    name = manifest.get('name')
                    if not name or name in seen_plugins:
                        continue  # Skip duplicates (local shadows global)
                    
                    taxonomy = self._parse_taxonomy(manifest)
                    resources = self._parse_resources(manifest)
                    derived_category = self._derive_category(manifest, taxonomy)
                    
                    # SG-35: `author` + `package_name` removed; `description`
                    # kept and validated by SG-6.
                    meta = PluginMeta(
                        name=name,
                        version=manifest.get('version', '0.0.0'),
                        description=manifest.get('description', ''),
                        category=derived_category,
                        interface=manifest.get('interface', ''),
                        taxonomy=taxonomy,
                        resources=resources,
                        config_schema=manifest.get('config_schema')
                    )
                    meta.manifest = manifest
                    
                    # SG-7: format-check the interface FQN; warn but still
                    # discover the manifest so older plugins remain usable.
                    self._check_interface_fqn(meta.interface, name)
                    
                    self.discovered.append(meta)
                    seen_plugins.add(name)
                    self.logger.info(f"Discovered manifest: {name} from {manifest_file}")

                except Exception as e:
                    self.logger.error(f"Error loading manifest {manifest_file}: {e}")

        return self.discovered

    def get_discovered_by_category(
        self,
        category:str # Category to filter by (e.g., "transcription")
    ) -> List[PluginMeta]: # List of matching discovered plugins
        """Get discovered plugins filtered by category."""
        return [meta for meta in self.discovered if meta.category == category]

    def get_plugins_by_category(
        self,
        category:str # Category to filter by (e.g., "transcription")
    ) -> List[PluginMeta]: # List of matching loaded plugins
        """Get loaded plugins filtered by category."""
        return [meta for meta in self.plugins.values() if meta.category == category]

    def get_discovered_categories(self) -> List[str]: # List of unique categories
        """Get all unique categories among discovered plugins."""
        return list(set(meta.category for meta in self.discovered if meta.category))

    def get_loaded_categories(self) -> List[str]: # List of unique categories
        """Get all unique categories among loaded plugins."""
        return list(set(meta.category for meta in self.plugins.values() if meta.category))

    def get_plugin_meta(
        self,
        plugin_name:str # Name of the plugin
    ) -> Optional[PluginMeta]: # Plugin metadata or None
        """Get metadata for a loaded plugin by name."""
        return self.plugins.get(plugin_name)

    def get_discovered_meta(
        self,
        plugin_name:str # Name of the plugin
    ) -> Optional[PluginMeta]: # Plugin metadata or None
        """Get metadata for a discovered (not necessarily loaded) plugin by name."""
        for meta in self.discovered:
            if meta.name == plugin_name:
                return meta
        return None

    def _extract_defaults_from_schema(
        self,
        config_schema:Optional[Dict[str, Any]] # JSON Schema with properties
    ) -> Dict[str, Any]: # Default values extracted from schema
        """Extract default values from a JSON Schema's properties."""
        if not config_schema:
            return {}

        properties = config_schema.get("properties", {})
        defaults = {}

        for field_name, field_schema in properties.items():
            if "default" in field_schema:
                defaults[field_name] = field_schema["default"]

        return defaults

    def _validate_config_against_schema(
        self,
        config:Optional[Dict[str, Any]], # Caller-provided config dict (or None)
        config_schema:Optional[Dict[str, Any]], # Plugin's JSON Schema from manifest
        plugin_name:str, # For error messages and warnings
        strict:bool=True # Reject unknown keys (default); set False to log+filter
    ) -> Dict[str, Any]: # Validated (possibly filtered) config dict
        """SG-5: validate a config dict against the manifest's `config_schema`
        before forwarding to the plugin's `initialize()`.
        """
        if config is None:
            return {}
        if not config_schema or "properties" not in config_schema:
            return dict(config)
        
        valid_keys = set(config_schema["properties"].keys())
        unknown_keys = sorted(set(config) - valid_keys)
        
        if unknown_keys:
            if strict:
                raise PluginConfigError(
                    f"Unknown config keys for plugin {plugin_name!r}: {unknown_keys}. "
                    f"Accepted keys per manifest config_schema: {sorted(valid_keys)}. "
                    f"Pass strict=False to ignore unknown keys (forward-compat).",
                    fields_invalid=unknown_keys,
                    config_class_name=plugin_name,
                )
            else:
                self.logger.warning(
                    "%s: ignoring unknown config keys %s (lenient mode)",
                    plugin_name, unknown_keys,
                )
                return {k: v for k, v in config.items() if k in valid_keys}
        
        return dict(config)

    def _check_config_schema_drift(
        self,
        proxy:Any, # RemotePluginProxy with a live worker
        plugin_meta:PluginMeta, # Metadata to flag if drift is detected
        manifest_schema:Optional[Dict[str, Any]] # Schema stored in the manifest
    ) -> None:
        """SG-9: compare live worker `/config_schema` to the manifest's stored schema."""
        try:
            live_schema = proxy.get_config_schema()
        except Exception as e:
            self.logger.debug(
                f"Skipping drift detection for {plugin_meta.name}: live schema fetch failed ({e})"
            )
            return
        
        if (manifest_schema or {}) != (live_schema or {}):
            plugin_meta.config_schema_drift = True
            plugin_meta.live_config_schema = live_schema
            self.logger.warning(
                f"Config schema drift for {plugin_meta.name}: manifest disagrees with live worker. "
                f"Run `cjm-ctl regenerate-manifest {plugin_meta.name}` to refresh the manifest."
            )

    def _persist_config(
        self,
        plugin_name: str  # Plugin to persist
    ) -> None:
        """CR-2: write current PluginMeta state + live worker config to the store.
        
        Reads `meta.enabled` (the substrate-authoritative flag) and the worker's
        current_config (when reachable). Failures are logged + swallowed —
        persistence is a best-effort side-channel, not a correctness invariant.
        """
        meta = self.plugins.get(plugin_name)
        if meta is None:
            return
        current_config: Dict[str, Any] = {}
        if meta.instance is not None:
            try:
                fetched = meta.instance.get_current_config()
                if isinstance(fetched, dict):
                    current_config = fetched
            except Exception as e:
                self.logger.debug(
                    f"Could not fetch live config for {plugin_name} during persist: {e}"
                )
        try:
            self.config_store.set(plugin_name, PluginConfigRecord(
                config=current_config,
                enabled=meta.enabled,
            ))
        except Exception as e:
            self.logger.warning(f"Failed to persist config for {plugin_name}: {e}")

    def _maybe_fire_disable_hook(
        self,
        name_or_id: str  # instance_id (or legacy plugin_name) whose in-flight job just finished
    ) -> None:
        """CR-2 + CR-10: fire deferred on_disable for `name_or_id` if pending.
        
        Idempotent. Resolves via self.instances first; falls back to
        self.plugins[name].instance for legacy code paths.
        """
        if name_or_id not in self._pending_disable_hooks:
            return
        self._pending_disable_hooks.discard(name_or_id)
        proxy = None
        inst = self.instances.get(name_or_id)
        if inst is not None:
            proxy = inst.proxy
        else:
            meta = self.plugins.get(name_or_id)
            if meta is not None:
                proxy = meta.instance
        if proxy is None:
            return
        try:
            proxy.on_disable()
        except Exception as e:
            self.logger.warning(f"on_disable() raised for {name_or_id}: {e}")

    # ------------------------------------------------------------------
    # CR-10: multi-instance bookkeeping helpers
    # ------------------------------------------------------------------
    
    def _validate_instance_id(self, instance_id: str) -> None:
        """Reject malformed explicit instance_ids at load time.
        
        Pattern: alphanumeric + underscore + hyphen, length 1..64. Raises
        ValueError on invalid input so the caller sees the constraint failure
        immediately rather than at first execute / unload.
        """
        import re as _re
        if not isinstance(instance_id, str):
            raise ValueError(
                f"instance_id must be str, got {type(instance_id).__name__}"
            )
        if not _re.fullmatch(r"[A-Za-z0-9_-]{1,64}", instance_id):
            raise ValueError(
                f"instance_id {instance_id!r} must match pattern [A-Za-z0-9_-]{{1,64}}"
            )
    
    def _generate_instance_id(self, plugin_name: str) -> str:
        """Generate a unique instance_id of form `{plugin_name}-{6-char-hex}`.
        
        Used when load_plugin is called with new_instance=True and no explicit
        instance_id. Retries up to 16 times if a collision occurs in self.instances.
        """
        import secrets as _secrets
        for _ in range(16):
            candidate = f"{plugin_name}-{_secrets.token_hex(3)}"
            if candidate not in self.instances:
                return candidate
        raise RuntimeError(
            f"Could not generate unique instance_id for {plugin_name!r} after 16 attempts"
        )
    
    def get_instance(
        self,
        name_or_id: str  # Plugin name (default-loaded) or explicit instance_id
    ) -> Optional[PluginInstance]:
        """Return the PluginInstance for `name_or_id`, or None if not loaded.
        
        Lookup is keyed by instance_id (which equals plugin_name for default-
        loaded plugins). Multi-instance IDs only exist in self.instances.
        """
        return self.instances.get(name_or_id)
    
    def list_instances(
        self,
        plugin_name: Optional[str] = None  # If given, filter to this plugin's instances
    ) -> List[PluginInstance]:
        """List all loaded instances, optionally filtered by underlying plugin name."""
        if plugin_name is None:
            return list(self.instances.values())
        return [i for i in self.instances.values() if i.plugin_name == plugin_name]
    
    def load_plugin(
        self,
        plugin_meta:PluginMeta, # Plugin metadata (with manifest attached)
        config:Optional[Dict[str, Any]]=None, # Initial configuration
        strict:bool=True, # SG-5: reject unknown keys against manifest config_schema (default)
        instance_id:Optional[str]=None, # CR-10: explicit instance_id; None defaults to plugin_name
        new_instance:bool=False # CR-10: auto-generate `{name}-{hex}` instance_id (with instance_id=None)
    ) -> bool: # True if successfully loaded
        """Load a plugin by spawning a Worker subprocess.
        
        CR-2: reads the persisted PluginConfigRecord from `self.config_store`
        before launching the worker. If a persisted record exists and the
        caller didn't pass an explicit config, the persisted config is used
        as the effective input. The persisted `enabled` flag is applied to
        `plugin_meta.enabled` so disabled plugins stay disabled across
        process restarts.
        
        CR-10: optional `instance_id` allows multi-instance loading.
        - instance_id=None, new_instance=False (default): instance_id =
          plugin_meta.name. Populates self.plugins[plugin_name] + self.instances
          [plugin_name] together (single-instance backward compat).
        - instance_id="custom": validated against `[A-Za-z0-9_-]{1,64}`. Populates
          self.instances[custom]. Persistence is keyed by plugin_name and only
          applied to the default instance.
        - instance_id=None, new_instance=True: auto-generates `{name}-{6-hex}`.
        Idempotent: re-load against an existing instance_id returns True without
        re-spawning.
        """
        if not hasattr(plugin_meta, 'manifest'):
            self.logger.error(f"Plugin {plugin_meta.name} has no manifest data")
            return False
        
        # CR-10: resolve instance_id + idempotency check
        if instance_id is None:
            resolved_id = self._generate_instance_id(plugin_meta.name) if new_instance else plugin_meta.name
        else:
            self._validate_instance_id(instance_id)
            resolved_id = instance_id
        if resolved_id in self.instances:
            self.logger.info(f"Instance {resolved_id!r} already loaded; idempotent skip")
            return True
        is_default = (resolved_id == plugin_meta.name)

        # CR-2: read persisted record (config + enabled flag) before launching.
        # Persistence is per-plugin (keyed by plugin_name), not per-instance, so
        # multi-instance loads ignore the persisted state.
        persisted: Optional[PluginConfigRecord] = None
        if is_default:
            try:
                persisted = self.config_store.get(plugin_meta.name)
            except Exception as e:
                self.logger.debug(
                    f"config_store.get({plugin_meta.name}) raised; falling through: {e}"
                )

        try:
            self.logger.info(
                f"Launching worker for {plugin_meta.name} (instance_id={resolved_id})..."
            )
            proxy = RemotePluginProxy(plugin_meta.manifest)

            config_schema = plugin_meta.manifest.get("config_schema")
            
            # SG-9: detect drift between manifest-declared schema and live worker.
            self._check_config_schema_drift(proxy, plugin_meta, config_schema)
            
            # CR-2: effective config = caller > persisted (default-only) > manifest defaults.
            if not config and persisted is not None and persisted.config:
                config = dict(persisted.config)
                self.logger.info(
                    f"Using persisted config for {plugin_meta.name}: {list(config.keys())}"
                )
            
            # If config is still None or empty, extract defaults from the
            # plugin's config schema (existing behavior).
            if not config:
                config = self._extract_defaults_from_schema(config_schema)
                if config:
                    self.logger.info(f"Using default config for {plugin_meta.name}: {list(config.keys())}")
            else:
                # SG-5: validate caller-provided / persisted config against
                # manifest schema before forwarding to the worker.
                config = self._validate_config_against_schema(
                    config, config_schema, plugin_meta.name, strict=strict,
                )

            # Initialize with config (defaults or provided)
            if config:
                proxy.initialize(config)

            # CR-10: per-instance enabled flag. Default instance restores from
            # persistence; multi-instance starts enabled.
            effective_enabled = True
            if is_default and persisted is not None:
                effective_enabled = persisted.enabled
                plugin_meta.enabled = effective_enabled
            
            # CR-10: always record the per-instance state
            self.instances[resolved_id] = PluginInstance(
                instance_id=resolved_id,
                plugin_name=plugin_meta.name,
                config=dict(config or {}),
                proxy=proxy,
                enabled=effective_enabled,
            )
            
            # Default-instance only: maintain backward-compat single-instance
            # references (PluginMeta.instance, self.plugins[plugin_name]).
            if is_default:
                plugin_meta.instance = proxy
                self.plugins[plugin_meta.name] = plugin_meta
            elif plugin_meta.name not in self.plugins:
                # First-ever instance for this plugin is multi-instance — record
                # the PluginMeta so list_plugins / get_plugin_meta still work,
                # but leave meta.instance=None (no canonical instance exists).
                self.plugins[plugin_meta.name] = plugin_meta
            
            self.logger.info(
                f"Loaded plugin: {plugin_meta.name} "
                f"(instance_id={resolved_id}, enabled={effective_enabled})"
            )
            return True

        except Exception as e:
            self.logger.error(
                f"Failed to load plugin {plugin_meta.name} (instance_id={resolved_id}): {e}"
            )
            return False

    def load_all(
        self,
        configs:Optional[Dict[str, Dict[str, Any]]]=None # Plugin name -> config mapping
    ) -> Dict[str, bool]: # Plugin name -> success mapping
        """Discover and load all available plugins."""
        configs = configs or {}
        results = {}
        
        self.discover_manifests()
        for meta in self.discovered:
            config = configs.get(meta.name)
            results[meta.name] = self.load_plugin(meta, config)
        
        return results

    def unload_plugin(
        self,
        name_or_id:str # Plugin name (default-loaded) or instance_id (multi-instance)
    ) -> bool: # True if successfully unloaded
        """Unload a plugin instance and terminate its Worker process (CR-10).
        
        If name_or_id resolves to the default instance (instance_id == plugin_name)
        and no other instances remain for the same plugin, also removes the
        PluginMeta from self.plugins. Otherwise removes only the instance and
        clears PluginMeta.instance if it pointed at the unloaded canonical.
        """
        inst = self.instances.get(name_or_id)
        if inst is None:
            self.logger.error(f"Plugin/instance {name_or_id!r} not found")
            return False
        plugin_name = inst.plugin_name
        instance_id = inst.instance_id
        try:
            if inst.proxy is not None:
                inst.proxy.cleanup()
            del self.instances[instance_id]
            self._pending_disable_hooks.discard(instance_id)
            self._running_executions.discard(instance_id)
            # Backward-compat: also clear plugin_name keys for the canonical instance
            self._pending_disable_hooks.discard(plugin_name)
            self._running_executions.discard(plugin_name)
            
            remaining = [i for i in self.instances.values() if i.plugin_name == plugin_name]
            if not remaining:
                # No instances of this plugin at all (whether the unloaded one
                # was canonical or multi-instance) — drop the PluginMeta entry.
                self.plugins.pop(plugin_name, None)
            elif instance_id == plugin_name:
                # Canonical instance unloaded but multi-instances remain — clear
                # the now-stale canonical reference; PluginMeta stays so
                # list_plugins / get_plugin_meta still surface the plugin.
                meta = self.plugins.get(plugin_name)
                if meta is not None:
                    meta.instance = None
            self.logger.info(f"Unloaded plugin: {plugin_name} (instance_id={instance_id})")
            return True
        except Exception as e:
            self.logger.error(f"Error unloading {name_or_id!r}: {e}")
            return False

    def unload_all(self) -> None:
        """Unload all plugin instances and terminate all Worker processes (CR-10).
        
        Iterates self.instances (CR-10 keying) rather than self.plugins so all
        multi-instance entries get torn down, not just the canonical instances.
        """
        for inst_id in list(self.instances.keys()):
            self.unload_plugin(inst_id)
        # Catch any legacy plugin entries that didn't have a corresponding instance
        # (shouldn't happen post-CR-10 but defensive cleanup)
        for name in list(self.plugins.keys()):
            self.unload_plugin(name)

    def get_plugin(
        self,
        name_or_id:str # Plugin name (default-loaded) or instance_id (multi-instance)
    ) -> Optional[PluginInterface]: # Plugin proxy instance or None
        """Get a loaded plugin's proxy by name or instance_id (CR-10).
        
        Lookup order: self.instances first (covers both default plugin_name and
        multi-instance IDs), falling back to PluginMeta.instance for any
        legacy code path that populated self.plugins without self.instances
        (defensive — shouldn't happen post-CR-10 since load_plugin always
        records the instance).
        """
        inst = self.instances.get(name_or_id)
        if inst is not None:
            return inst.proxy
        meta = self.plugins.get(name_or_id)
        return meta.instance if meta else None

    def list_plugins(self) -> List[PluginMeta]: # List of loaded plugin metadata
        """List all loaded plugins."""
        return list(self.plugins.values())

    def _evict_for_resources(self, needed_meta:PluginMeta) -> bool:
        """Attempt to free resources by unloading/releasing idle plugins (LRU)."""
        self.logger.info(f"Attempting eviction to make room for {needed_meta.name}...")
        
        candidates = [
            meta for name, meta in self.plugins.items()
            if meta.instance 
            and name != needed_meta.name
            and meta.manifest.get('resources', {}).get('requires_gpu', False)
        ]
        candidates.sort(key=lambda x: x.last_executed)
        
        for candidate in candidates:
            self.logger.info(f"Evicting idle plugin: {candidate.name} (Last used: {candidate.last_executed})")
            if hasattr(candidate.instance, 'release'):
                candidate.instance.release()
            else:
                self.reload_plugin(candidate.name)
            time.sleep(0.5) 
            if self.scheduler.allocate(needed_meta, self._get_global_stats):
                return True
                
        return False

    def execute_plugin(
        self,
        name_or_id:str, # Plugin name (default-loaded) or instance_id (multi-instance)
        *args,
        **kwargs
    ) -> Any: # Plugin result
        """Execute a plugin instance's main functionality (sync).
        
        CR-10: resolves `name_or_id` via self.instances; per-instance enabled
        flag gates execution. `_running_executions` tracks by instance_id so
        concurrent multi-instance executes don't collide.
        
        CR-2: raises PluginDisabledError (typed) when the instance is disabled.
        """
        inst = self.instances.get(name_or_id)
        if inst is None:
            raise ValueError(f"Plugin/instance {name_or_id!r} not found or not loaded")
        if not inst.enabled:
            raise PluginDisabledError(inst.instance_id)
        
        # Per-instance last_executed + canonical PluginMeta sync (scheduler
        # eviction reads from PluginMeta, so keep it in sync for default
        # instance at minimum).
        inst.last_executed = time.time()
        plugin_meta = self.plugins.get(inst.plugin_name)
        if plugin_meta is not None:
            plugin_meta.last_executed = inst.last_executed
        stats_provider = self._get_global_stats
        
        # Scheduler allocation uses PluginMeta (plugin-level resource constraints).
        if plugin_meta is not None and not self.scheduler.allocate(plugin_meta, stats_provider):
            self.logger.warning(f"Resources busy for {name_or_id}. Triggering eviction protocol.")
            if self._evict_for_resources(plugin_meta):
                self.logger.info("Eviction successful. Resources acquired.")
            else:
                raise RuntimeError(
                    f"ResourceScheduler blocked execution of {name_or_id} (Eviction failed)"
                )

        # CR-10: track per-instance to allow concurrent multi-instance executes.
        self._running_executions.add(inst.instance_id)
        self.scheduler.on_execution_start(inst.instance_id)
        try:
            return inst.proxy.execute(*args, **kwargs)
        finally:
            self.scheduler.on_execution_finish(inst.instance_id)
            self._running_executions.discard(inst.instance_id)
            # If disable_plugin() deferred on_disable while this job ran, fire now.
            self._maybe_fire_disable_hook(inst.instance_id)

    async def execute_plugin_async(
        self,
        name_or_id:str, # Plugin name (default-loaded) or instance_id (multi-instance)
        *args,
        **kwargs
    ) -> Any: # Plugin result
        """Execute a plugin instance's main functionality (async).
        
        CR-10 + CR-2: same semantics as execute_plugin, async-flavored. Scheduler
        allocation goes through allocate_async for non-blocking polling.
        """
        inst = self.instances.get(name_or_id)
        if inst is None:
            raise ValueError(f"Plugin/instance {name_or_id!r} not found or not loaded")
        if not inst.enabled:
            raise PluginDisabledError(inst.instance_id)
        
        inst.last_executed = time.time()
        plugin_meta = self.plugins.get(inst.plugin_name)
        if plugin_meta is not None:
            plugin_meta.last_executed = inst.last_executed
        
        if plugin_meta is not None and not await self.scheduler.allocate_async(plugin_meta, self._get_global_stats_async):
            self.logger.warning(f"Resources busy for {name_or_id}. Triggering eviction protocol.")
            if self._evict_for_resources(plugin_meta):
                self.logger.info("Eviction successful. Resources acquired.")
            else:
                raise RuntimeError(
                    f"ResourceScheduler blocked execution of {name_or_id} (Eviction failed)"
                )

        self._running_executions.add(inst.instance_id)
        self.scheduler.on_execution_start(inst.instance_id)
        try:
            return await inst.proxy.execute_async(*args, **kwargs)
        finally:
            self.scheduler.on_execution_finish(inst.instance_id)
            self._running_executions.discard(inst.instance_id)
            self._maybe_fire_disable_hook(inst.instance_id)

    def enable_plugin(
        self,
        name_or_id:str # Plugin name (default instance) or instance_id (multi-instance)
    ) -> bool: # True if instance was enabled
        """Enable a plugin instance (CR-10 multi-instance aware).
        
        CR-2: persists the new state via `config_store` (default-instance only;
        persistence is per-plugin, not per-instance) and fires the plugin's
        on_enable hook on state-change. Idempotent for already-enabled instances.
        """
        inst = self.instances.get(name_or_id)
        if inst is None:
            return False
        was_disabled = not inst.enabled
        inst.enabled = True
        # Default instance: also sync the PluginMeta.enabled flag (backward compat)
        # and persist via config_store (per-plugin persistence).
        if inst.instance_id == inst.plugin_name:
            meta = self.plugins.get(inst.plugin_name)
            if meta is not None:
                meta.enabled = True
            self._persist_config(inst.plugin_name)
        if was_disabled and inst.proxy is not None:
            try:
                inst.proxy.on_enable()
            except Exception as e:
                self.logger.warning(f"on_enable() raised for {name_or_id}: {e}")
        return True

    def disable_plugin(
        self,
        name_or_id:str # Plugin name (default instance) or instance_id (multi-instance)
    ) -> bool: # True if instance was disabled
        """Disable a plugin instance without unloading it (CR-10 multi-instance aware).
        
        CR-2: persists the new state (default-instance only) and fires the
        plugin's on_disable hook — but defers the hook until any in-flight job
        for THIS instance finishes (the per-instance `_running_executions` key
        is the instance_id, so a concurrent execute on a different instance of
        the same plugin doesn't gate this instance's hook).
        """
        inst = self.instances.get(name_or_id)
        if inst is None:
            return False
        was_enabled = inst.enabled
        inst.enabled = False
        # Default instance: sync PluginMeta.enabled + persist
        if inst.instance_id == inst.plugin_name:
            meta = self.plugins.get(inst.plugin_name)
            if meta is not None:
                meta.enabled = False
            self._persist_config(inst.plugin_name)
        if was_enabled and inst.proxy is not None:
            if inst.instance_id in self._running_executions:
                self._pending_disable_hooks.add(inst.instance_id)
                self.logger.debug(
                    f"Deferring on_disable() for {inst.instance_id} until in-flight job finishes"
                )
            else:
                try:
                    inst.proxy.on_disable()
                except Exception as e:
                    self.logger.warning(f"on_disable() raised for {name_or_id}: {e}")
        return True

    def get_plugin_logs(
        self,
        plugin_name:str, # Name of the plugin
        lines:int=50 # Number of lines to return
    ) -> str: # Log content
        """Read the last N lines of the plugin's log file."""
        cfg = get_config()
        log_path = cfg.logs_dir / f"{plugin_name}.log"
        
        if not log_path.exists():
            return "No logs found."
            
        try:
            from collections import deque
            with open(log_path, 'r') as f:
                tail = deque(f, maxlen=lines)
                return "".join(tail)
        except Exception as e:
            return f"Error reading logs: {e}"

